package com.example.bank.ws.security;

import jakarta.xml.ws.handler.MessageContext;
import jakarta.xml.ws.handler.soap.SOAPMessageContext;
import org.w3c.dom.*;
import javax.xml.namespace.QName;
import jakarta.xml.soap.SOAPMessage;
import jakarta.xml.soap.SOAPPart;
import jakarta.xml.soap.SOAPEnvelope;
import jakarta.xml.soap.SOAPHeader;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public final class SignatureExtraction {

    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String DSIG_NS = "http://www.w3.org/2000/09/xmldsig#";

    private SignatureExtraction() {}

    public static final class ExtractedSecurity {
        private final Element securityHeader;
        private final Element signatureElement;
        private final List<Element> signedElements;

        public ExtractedSecurity(Element securityHeader, Element signatureElement, List<Element> signedElements) {
            this.securityHeader = securityHeader;
            this.signatureElement = signatureElement;
            this.signedElements = signedElements != null ? signedElements : Collections.emptyList();
        }

        public Element getSecurityHeader() {
            return securityHeader;
        }

        public Element getSignatureElement() {
            return signatureElement;
        }

        public List<Element> getSignedElements() {
            return signedElements;
        }
    }

    public static ExtractedSecurity extractFromInboundMessageContext(MessageContext mc) {
        if (!(mc instanceof SOAPMessageContext)) return null;
        SOAPMessageContext smc = (SOAPMessageContext) mc;

        Boolean outbound = (Boolean) smc.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (outbound != null && outbound) return null;

        try {
            SOAPMessage soapMessage = smc.getMessage();
            SOAPPart part = soapMessage.getSOAPPart();
            SOAPEnvelope envelope = part.getEnvelope();
            SOAPHeader header = envelope.getHeader();
            if (header == null) return null;

            NodeList securityNodes = header.getElementsByTagNameNS(WSSE_NS, "Security");
            if (securityNodes.getLength() == 0) return null;
            Element security = (Element) securityNodes.item(0);

            Element signature = firstElementByTagNameNS(security, DSIG_NS, "Signature");
            if (signature == null) return new ExtractedSecurity(security, null, Collections.emptyList());

            List<Element> signed = extractSignedElements(envelope, signature);
            return new ExtractedSecurity(security, signature, signed);
        } catch (Exception e) {
            return null;
        }
    }

    private static List<Element> extractSignedElements(SOAPEnvelope envelope, Element signatureElement) {
        Element signedInfo = firstElementByTagNameNS(signatureElement, DSIG_NS, "SignedInfo");
        if (signedInfo == null) return Collections.emptyList();

        NodeList refs = signedInfo.getElementsByTagNameNS(DSIG_NS, "Reference");
        if (refs == null || refs.getLength() == 0) return Collections.emptyList();

        List<Element> out = new ArrayList<>();
        Document doc = envelope.getOwnerDocument();

        for (int i = 0; i < refs.getLength(); i++) {
            Element ref = (Element) refs.item(i);
            String uri = ref.getAttribute("URI");
            if (uri == null || uri.isBlank() || !uri.startsWith("#")) continue;

            String id = uri.substring(1);
            Element target = findElementByWsuId(doc, id);
            if (target == null) {
                target = findElementByAnyId(doc, id);
            }
            if (target != null) out.add(target);
        }
        return out;
    }

    private static Element findElementByWsuId(Document doc, String id) {
        NodeList all = doc.getElementsByTagName("*");
        for (int i = 0; i < all.getLength(); i++) {
            Node n = all.item(i);
            if (n.getNodeType() != Node.ELEMENT_NODE) continue;
            Element e = (Element) n;
            if (e.hasAttributeNS(WSU_NS, "Id")) {
                String v = e.getAttributeNS(WSU_NS, "Id");
                if (id.equals(v)) return e;
            }
        }
        return null;
    }

    private static Element findElementByAnyId(Document doc, String id) {
        NodeList all = doc.getElementsByTagName("*");
        for (int i = 0; i < all.getLength(); i++) {
            Node n = all.item(i);
            if (n.getNodeType() != Node.ELEMENT_NODE) continue;
            Element e = (Element) n;
            if (e.hasAttribute("Id") && id.equals(e.getAttribute("Id"))) return e;
            if (e.hasAttribute("ID") && id.equals(e.getAttribute("ID"))) return e;
            if (e.hasAttribute("id") && id.equals(e.getAttribute("id"))) return e;
        }
        return null;
    }

    private static Element firstElementByTagNameNS(Element parent, String ns, String localName) {
        NodeList nl = parent.getElementsByTagNameNS(ns, localName);
        if (nl.getLength() == 0) return null;
        Node n = nl.item(0);
        if (n.getNodeType() != Node.ELEMENT_NODE) return null;
        return (Element) n;
    }
}

