public final class CxfWss4jFeature extends AbstractFeature {

    private final Properties cryptoProps;
    private final String signatureUsername;

    public CxfWss4jFeature(Properties cryptoProps, String signatureUsername) {
        this.cryptoProps = cryptoProps;
        this.signatureUsername = signatureUsername;
    }

    @Override
    protected void initializeProvider(InterceptorProvider provider, Bus bus) {
        Map<String, Object> inProps = new HashMap<>();
        inProps.put("action", "Signature");
        inProps.put("signaturePropRefId", "cryptoProps");
        inProps.put("cryptoProps", cryptoProps);

        Map<String, Object> outProps = new HashMap<>();
        outProps.put("action", "Signature");
        outProps.put("user", signatureUsername);
        outProps.put("signaturePropRefId", "cryptoProps");
        outProps.put("cryptoProps", cryptoProps);

        provider.getInInterceptors().add(new WSS4JInInterceptor(inProps));
        provider.getOutInterceptors().add(new WSS4JOutInterceptor(outProps));
    }
}

package com.example.bank.ws.security;

import java.io.InputStream;
import java.security.KeyStore;
import java.security.PublicKey;
import java.security.cert.Certificate;

public final class KeyMaterial {

    private KeyMaterial() {}

    public static PublicKey loadVerificationPublicKeyFromKeystore(InputStream jksStream, char[] storePassword, String alias) {
        try {
            KeyStore ks = KeyStore.getInstance("JKS");
            ks.load(jksStream, storePassword);
            Certificate cert = ks.getCertificate(alias);
            if (cert == null) throw new IllegalStateException("No certificate for alias: " + alias);
            return cert.getPublicKey();
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}

package com.example.bank.ws.server;

import com.example.bank.ws.BankingServiceImpl;
import com.example.bank.ws.TransactionProcessor;
import com.example.bank.ws.security.CxfWss4jFeature;
import com.example.bank.ws.security.KeyMaterial;
import org.apache.cxf.Bus;
import org.apache.cxf.bus.extension.ExtensionManagerBus;
import org.apache.cxf.jaxws.JaxWsServerFactoryBean;

import java.io.FileInputStream;
import java.io.InputStream;
import java.security.PublicKey;
import java.util.Properties;

public final class BankingServicePublisher {

    public static void main(String[] args) throws Exception {
        String address = System.getProperty("bank.ws.address", "http://0.0.0.0:8080/bank/BankingService");

        String keystorePath = System.getProperty("bank.ws.keystore.path", "config/bank.jks");
        String keystorePassword = System.getProperty("bank.ws.keystore.password", "changeit");
        String certAlias = System.getProperty("bank.ws.verify.cert.alias", "bank-client");

        String cryptoPropertiesPath = System.getProperty("bank.ws.crypto.properties", "config/crypto.properties");
        String signUser = System.getProperty("bank.ws.sign.user", "bank-service");

        PublicKey verificationKey;
        try (InputStream in = new FileInputStream(keystorePath)) {
            verificationKey = KeyMaterial.loadVerificationPublicKeyFromKeystore(in, keystorePassword.toCharArray(), certAlias);
        }

        TransactionProcessor processor = new TransactionProcessor();
        BankingServiceImpl implementor = new BankingServiceImpl(verificationKey, processor);

        Properties cryptoProps = new Properties();
        try (InputStream in = new FileInputStream(cryptoPropertiesPath)) {
            cryptoProps.load(in);
        }

        Bus bus = new ExtensionManagerBus();

        JaxWsServerFactoryBean factory = new JaxWsServerFactoryBean();
        factory.setBus(bus);
        factory.setServiceBean(implementor);
        factory.setAddress(address);
        factory.getFeatures().add(new CxfWss4jFeature(cryptoProps, signUser));

        factory.create();

        Thread.currentThread().join();
    }
}